// Validação de entrada do Workflow 01
const inputData = $input.first().json;

// Validação crítica do phone_number
if (!inputData.phone_number || inputData.phone_number === 'undefined') {
    throw new Error('Phone number is required but was not received from Workflow 01');
}

// Limpar e validar formato do phone_number
let phone_number = String(inputData.phone_number).replace(/[^0-9]/g, '');

// Remover @s.whatsapp.net se existir
if (phone_number.includes('@')) {
  phone_number = phone_number.split('@')[0];
}

// IMPORTANTE: Adicionar código 55 se não tiver (MOVIDO DO PREPARE UPDATE DATA)
if (phone_number && !phone_number.startsWith('55')) {
  // Se tem 10 ou 11 dígitos (formato brasileiro), adiciona 55
  if (phone_number.length === 10 || phone_number.length === 11) {
    phone_number = '55' + phone_number;
    console.log('Adicionado código 55:', phone_number);
  }
  // Se tem 12 ou 13 dígitos começando com outro código, mantém
  else if (phone_number.length >= 12) {
    console.log('Número já tem código de país:', phone_number);
  }
  // Qualquer outro caso, tenta adicionar 55
  else {
    phone_number = '55' + phone_number;
    console.log('Formato desconhecido, adicionado 55:', phone_number);
  }
}

// Validação de formato brasileiro (DDD + número) - AGORA COM 55
if (phone_number.length < 12 || phone_number.length > 13) {
    console.warn(`Phone number format unusual: ${phone_number} (expected 12-13 digits with country code)`);
}

console.log('Validated input:', {
    phone_number: phone_number,  // Agora já tem 55
    whatsapp_name: inputData.whatsapp_name,
    message_type: inputData.message_type
});

return {
    phone_number: phone_number,  // COM código 55
    whatsapp_name: inputData.whatsapp_name || '',
    message: inputData.message || '',
    message_type: inputData.message_type || 'text',
    media_url: inputData.media_url || null,
    message_id: inputData.message_id || '',
    timestamp: inputData.timestamp || new Date().toISOString()
};

// Prepare both phone formats for SQL queries
// This node receives data directly from WEBHOOK (not from Validate Input Data)
const inputData = $input.first().json;

// Get phone number - could come from webhook or validate input
let phone_with_code = String(inputData.phone_number || '');

// Clean the phone number
phone_with_code = phone_with_code.replace(/[^0-9]/g, '');

// Add country code if missing
if (phone_with_code && !phone_with_code.startsWith('55')) {
    if (phone_with_code.length === 10 || phone_with_code.length === 11) {
        phone_with_code = '55' + phone_with_code;
        console.log('Added country code 55:', phone_with_code);
    }
}

// Create version without country code for compatibility
let phone_without_code = phone_with_code;
if (phone_with_code.startsWith('55')) {
    phone_without_code = phone_with_code.substring(2);
}

console.log('=== PHONE FORMAT PREPARATION ===');
console.log('With code (55):', phone_with_code);
console.log('Without code:', phone_without_code);

// Return both formats and pass through all other data
return {
    ...inputData, // Pass through all original data
    phone_with_code: phone_with_code,      // e.g., "556181755748"
    phone_without_code: phone_without_code, // e.g., "6181755748"
    // Keep original for compatibility
    phone_number: phone_with_code,

    // CRITICAL V26 FIX: Ensure ALL possible message field names are present
    // This handles different webhook formats from Evolution API
    message: inputData.message || inputData.body || inputData.text || inputData.content || '',
    content: inputData.content || inputData.message || inputData.body || inputData.text || '',
    body: inputData.body || inputData.message || inputData.text || inputData.content || '',
    text: inputData.text || inputData.message || inputData.body || inputData.content || '',

    // Also ensure whatsapp_name is present
    whatsapp_name: inputData.whatsapp_name || inputData.pushName || inputData.profileName || ''
};

